class ApprovalAgent(BaseAgent):
    def __init__(self):
        super().__init__(model='gemini-2.0-flash')

    async def validate_send(self, draft: str, recipients: list, attachments: list) -> bool:
        checks = await self.run({
            'draft': draft,
            'recipients': recipients,
            'attachments': attachments
        })
        return all([
            checks['tone_appropriate'],
            checks['recipients_valid'],
            checks['no_pii'],
            checks['confidentiality_ok']
        ])

